import { Registry } from '../../core/zc-registry';
import { d3_min } from '../../core/d3-constants';
import { geometryUtils } from '../../utils/geometry-utils';

export function closestToPolygon(polygonPoints, point) {
    let [x, y] = point,
        distances = polygonPoints.map(_ => geometryUtils.dist({ x: _[0], y: _[1] }, { x, y })),
        closet = d3_min(distances);

    return closet || 0;
}

Registry.setComponent('geometryUtils.polygon.closestToPolygon', closestToPolygon);
